package com.alsa.alsacleanfleet.controller;import com.alsa.alsacleanfleet.dto.*;import com.alsa.alsacleanfleet.service.NettoyageService;import jakarta.validation.Valid;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController @RequestMapping("/api/nettoyages") public class NettoyageController{private final NettoyageService s;public NettoyageController(NettoyageService s){this.s=s;}@GetMapping public List<NettoyageResponseDTO> all(){return s.findAll();}@GetMapping("/{id}")public NettoyageResponseDTO one(@PathVariable Long id){return s.findById(id);}@GetMapping("/statistiques")public Map<String,Long> stats(){return s.statistics();}@PostMapping public ResponseEntity<NettoyageResponseDTO> add(@Valid @RequestBody NettoyageRequestDTO d){return ResponseEntity.status(HttpStatus.CREATED).body(s.create(d));}@PutMapping("/{id}")public NettoyageResponseDTO edit(@PathVariable Long id,@Valid @RequestBody NettoyageRequestDTO d){return s.update(id,d);}@DeleteMapping("/{id}")public ResponseEntity<Void> del(@PathVariable Long id){s.delete(id);return ResponseEntity.noContent().build();}}
